// Transmisión de datos GPS y sensores en tiempo real
const pipeline = new StreamProcessor({
  source: 'fleet-telemetry',
  processors: [
    new GPSProcessor(),
    new SensorProcessor(),
    new EventProcessor()
  ],
  sink: 'your-cloud-storage',
  latency: '< 56ms'
});

pipeline.start();
// Stream activo: Procesando 10K+ eventos/seg

